import React, { Component } from "react";
import ProjectDetailsModal from "./ProjectDetailsModal";
import { motion } from "framer-motion";

class Projects extends Component {
  constructor(props) {
    super(props);
    this.state = {
      deps: {},
      detailsModalShow: false,
      isVisible: false
    };

    this.sectionRef = React.createRef();
  }

  componentDidMount() {
    this.observer = new IntersectionObserver(
      ([entry]) => {
        this.setState({ isVisible: entry.isIntersecting });
      },
      { threshold: 0.25 } // Trigger slightly earlier for better UX
    );

    if (this.sectionRef.current) {
      this.observer.observe(this.sectionRef.current);
    }
  }

  componentWillUnmount() {
    if (this.observer && this.sectionRef.current) {
      this.observer.unobserve(this.sectionRef.current);
    }
  }

  render() {
    let detailsModalShow = (data) => {
      this.setState({ detailsModalShow: true, deps: data });
    };

    let detailsModalClose = () =>
      this.setState({ detailsModalShow: false });

    let sectionName, projects;

    if (this.props.resumeProjects && this.props.resumeBasicInfo) {
      sectionName = this.props.resumeBasicInfo.section_name.projects;

      projects = this.props.resumeProjects.map((projects, i) => {
        return (
          <motion.div
            className="col-sm-12 col-md-6 col-lg-4"
            key={projects.title}
            style={{ cursor: "pointer", padding: "15px" }}
            initial={{ opacity: 0, scale: 0.9, y: 30 }}
            animate={
              this.state.isVisible
                ? { opacity: 1, scale: 1, y: 0 }
                : { opacity: 0, scale: 0.9, y: 30 }
            }
            transition={{
              duration: 0.5,
              delay: i * 0.1,
              ease: "backOut"
            }}
            whileHover={{ y: -10 }} // Elegant lift effect
          >
            <span className="portfolio-item d-block">
              <div
                className="foto"
                onClick={() => detailsModalShow(projects)}
                style={{ background: "transparent" }}
              >
                <div
                  style={{
                    minHeight: "260px",
                    padding: "20px",
                    display: "flex",
                    flexDirection: "column",
                    justifyContent: "space-between",
                    borderRadius: "15px",
                    // Glassmorphism effect
                    background: "var(--card-background, rgba(255, 255, 255, 0.05))",
                    backdropFilter: "blur(10px)",
                    border: "1px solid rgba(255, 255, 255, 0.1)",
                    boxShadow: "0 10px 30px rgba(0,0,0,0.15)",
                    transition: "all 0.3s ease"
                  }}
                >
                  <div>
                    {/* Date Badge */}
                    <div style={{ display: 'flex', justifyContent: 'flex-start' }}>
                        <span className="project-date" style={{ 
                            borderRadius: '15px', 
                            fontSize: '11px', 
                            padding: '4px 12px',
                            background: '#AE944F' 
                        }}>
                            {projects.startDate}
                        </span>
                    </div>

                    {/* Title */}
                    <h2 className="project-title-settings" style={{ 
                        fontSize: '1.8rem', 
                        textAlign: 'left', 
                        marginTop: '15px',
                        color: 'var(--header-text, #333)'
                    }}>
                        {projects.title}
                    </h2>

                    {/* Description */}
                    <p style={{
                        fontSize: "13px",
                        textAlign: "left",
                        marginTop: "10px",
                        color: "var(--text-color)",
                        opacity: 0.8,
                        lineHeight: '1.5'
                    }}>
                        {projects.description}
                    </p>
                  </div>

                  {/* Footer link hint */}
                  <div style={{ 
                      fontSize: '11px', 
                      fontWeight: '700', 
                      letterSpacing: '1px', 
                      color: '#AE944F',
                      marginTop: '15px' 
                  }}>
                      VIEW DETAILS →
                  </div>
                </div>
              </div>
            </span>
          </motion.div>
        );
      });
    }

    return (
      <section id="portfolio" ref={this.sectionRef} style={{ padding: '60px 0' }}>
        <div className="col-md-12">

          {/* Title */}
          <motion.h1
            className="section-title"
            style={{ 
                color: "var(--header-text, black)", // Removed hardcoded "black"
                marginBottom: '50px' 
            }}
            initial={{ opacity: 0, y: -20 }}
            animate={
              this.state.isVisible
                ? { opacity: 1, y: 0 }
                : { opacity: 0, y: -20 }
            }
            transition={{ duration: 0.6 }}
          >
            <span>{sectionName}</span>
          </motion.h1>

          <div className="col-md-11 mx-auto">
            <div className="row mx-auto">{projects}</div>
          </div>

          <ProjectDetailsModal
            show={this.state.detailsModalShow}
            onHide={detailsModalClose}
            data={this.state.deps}
          />
        </div>
      </section>
    );
  }
}

export default Projects;
